import json, ast, re, pandas as pd

# Load business data from the file path stored in var_call_LUP1NwhYG5Y6GrCQZDNYrK5U
business_path = var_call_LUP1NwhYG5Y6GrCQZDNYrK5U
with open(business_path, 'r', encoding='utf-8') as f:
    businesses = json.load(f)

reviews = var_call_N7SWkFsfAsHtLh617ADrcUTJ

# DataFrames
df_bus = pd.DataFrame(businesses)
df_rev = pd.DataFrame(reviews)

# Normalize review avg_rating to float
df_rev['avg_rating'] = df_rev['avg_rating'].astype(float)

# Merge
df = pd.merge(df_bus, df_rev[['gmap_id','avg_rating']], on='gmap_id', how='inner')

# Helper functions

def parse_hours_field(s):
    if s is None:
        return []
    if isinstance(s, str) and s.strip().lower() == 'none':
        return []
    try:
        return ast.literal_eval(s)
    except Exception:
        return []


def time_to_minutes(t):
    if t is None:
        return None
    t = t.strip()
    if t.lower() == 'closed':
        return None
    # Extract hour, minute, am/pm
    m = re.match(r"^(\d{1,2})(?::(\d{2}))?\s*([AaPp][Mm])$", t)
    if not m:
        # Try to separate if AM/PM attached without space
        m = re.match(r"^(\d{1,2})(?::(\d{2}))?([AaPp][Mm])$", t)
    if not m:
        return None
    hour = int(m.group(1))
    minute = int(m.group(2)) if m.group(2) else 0
    ampm = m.group(3).upper()
    if ampm == 'AM':
        if hour == 12:
            hour = 0
    else:  # PM
        if hour != 12:
            hour += 12
    return hour * 60 + minute


def closes_after_6pm(hours_field):
    parsed = parse_hours_field(hours_field)
    weekdays = set(['Monday','Tuesday','Wednesday','Thursday','Friday'])
    for entry in parsed:
        if not isinstance(entry, (list, tuple)) or len(entry) < 2:
            continue
        day = entry[0]
        timestr = entry[1]
        if day not in weekdays:
            continue
        if not isinstance(timestr, str):
            continue
        # split on en-dash or hyphen
        if '\u2013' in timestr:
            parts = timestr.split('\u2013')
        elif '–' in timestr:
            parts = timestr.split('–')
        elif '-' in timestr:
            parts = timestr.split('-')
        else:
            parts = [timestr]
        if len(parts) < 2:
            continue
        end = parts[-1].strip()
        # sometimes end includes multiple times (unlikely) - take last token
        end_token = end.split()[-1]
        end_minutes = time_to_minutes(end_token)
        if end_minutes is None:
            continue
        if end_minutes > 18 * 60:
            return True
    return False

# Apply filter
 df = df.copy()
df['opens_after_6pm_weekday'] = df['hours'].apply(closes_after_6pm)

# Filter businesses that remain open after 6pm on at least one weekday
df_filtered = df[df['opens_after_6pm_weekday'] == True].copy()

# Sort by avg_rating desc and take top 5
df_filtered['avg_rating'] = df_filtered['avg_rating'].astype(float)
df_top5 = df_filtered.sort_values(by='avg_rating', ascending=False).head(5)

# Prepare output
result = []
for _, row in df_top5.iterrows():
    result.append({
        'name': row.get('name'),
        'hours': row.get('hours'),
        'avg_rating': round(float(row.get('avg_rating')), 4)
    })

import json
print("__RESULT__:")
print(json.dumps(result))

